   582→            "must" | "must_have" | "critical" => return 1,
   583→            "should" | "should_have" | "important" => return 2,
   584→            "could" | "could_have" | "nice_to_have" => return 3,
   585→            _ => {}
   586→        }
   587→        if let Ok(n) = s.parse::<i64>() {
   588→            return n;
   589→        }
   590→    }
   591→    3
   592→}
